using System.Collections.Generic;
using System.Linq;
using Microsoft.AspNetCore.Mvc;
using YourNamespace.Models; // Replace with your actual namespace

namespace YourNamespace.Controllers
{
    public class ProductController : Controller
    {
        private readonly YourDbContext _context; // Replace with your actual DbContext

        public ProductController(YourDbContext context)
        {
            _context = context;
        }

        public IActionResult ShowReviews(int productId)
        {
            var reviews = _context.Reviews
                .Where(r => r.ProductId == productId)
                .ToList();

            return View(reviews);
        }
    }
